const e=[{type:"hero",title:"The Slide Engine",subtitle:"A reusable, local-first presentation framework built with Vite + React.",notes:"Opening slide. Introduce the engine and its purpose. Emphasize that it is local-first — no cloud, no accounts."},{type:"section",title:"Getting Started",subtitle:"Everything you need to create your first deck.",icon:"🚀",notes:"Transition into the how-to section. Keep energy up."},{type:"bullet",title:"Core Principles",subtitle:"Four ideas that drive every design decision.",points:["Content lives in decks, never in the engine","Layouts are generic and accept typed props","Navigation is keyboard-first and instant","Theming is centralized in a single token file"],notes:'Walk through each principle slowly. Pause on "content lives in decks" — this is the key insight that makes the engine reusable.'},{type:"comparison",title:"Before vs. After",left:{heading:"Traditional Approach",points:["Slide decks tied to a specific tool","Content scattered across files","Hard to version-control","No keyboard shortcuts"]},right:{heading:"Slide Engine",points:["Portable, open-source, no lock-in","All content in typed TypeScript files","Git-friendly by default","Keyboard-first navigation built in"]},notes:"This is a good moment to ask: what tool do people use today? Keynote, Google Slides, PowerPoint?"},{type:"diagram",title:"System Architecture",layers:[{icon:"📄",label:"Deck Files",description:"manifest.ts + slides.ts — your content, fully typed",color:"#6366f1"},{icon:"⚙️",label:"Slide Router",description:"Reads the slides array, resolves types to layout components",color:"#8b5cf6"},{icon:"🖼️",label:"Layout Components",description:"Hero, Bullet, Comparison, etc. — generic, prop-driven",color:"#a78bfa"},{icon:"🎨",label:"Theme Tokens",description:"CSS custom properties from theme.ts, overridable per-deck",color:"#c4b5fd"}],notes:"Walk through each layer top-to-bottom. Emphasize the separation of concerns."},{type:"proof-point",title:"Developer Experience",metric:"< 2min",metricLabel:"from idea to first slide on screen",narrative:"Run npm run new-deck, edit two files, refresh. That is the entire workflow. No config, no build step decisions.",comparison:"vs. 30+ min in traditional tools",notes:"Let this metric breathe. Two minutes is surprisingly fast. Ask if anyone has timed how long it takes them to start a new deck in their current tool."},{type:"icon-card",title:"Nine Slide Types",cards:[{icon:"⭐",label:"Hero",description:"Big statement opener or closer"},{icon:"📑",label:"Section",description:"Chapter divider with optional icon"},{icon:"•••",label:"Bullet",description:"Heading with supporting points"},{icon:"⚖️",label:"Comparison",description:"Side-by-side two-column layout"},{icon:"🗂️",label:"Diagram",description:"Layered architecture visual"},{icon:"📊",label:"Proof Point",description:"Big metric with narrative"},{icon:"🃏",label:"Icon Card",description:"Grid of cards (this slide!)"},{icon:'"',label:"Quote",description:"Featured callout text"},{icon:"📅",label:"Timeline",description:"Sequential event chain"}],columns:3,notes:"Point out that this slide is itself an icon-card slide. Meta!"},{type:"quote",text:"The best presentation tool is the one that gets out of your way and lets the ideas speak.",attribution:"Slide Engine README",notes:"Let this one sit for a moment. It encapsulates the philosophy."},{type:"timeline",title:"Getting to Production",items:[{icon:"📁",label:"Clone the repo",description:"git clone and npm install"},{icon:"🆕",label:"Create a deck",description:"npm run new-deck my-presentation"},{icon:"✏️",label:"Write your slides",description:"Edit manifest.ts and slides.ts"},{icon:"🎯",label:"Present",description:"npm run dev, open browser, press F for fullscreen"}],notes:"Step-by-step walkthrough. Offer to do a live demo after the talk."},{type:"hero",title:"Start Building.",subtitle:"npm run new-deck your-idea",notes:"End on a call to action. Leave the command visible so people can write it down."}];